if (! function_exists('earthquake_monitor')) {
    function earthquake_monitor($period = null, $min_magnitude = null, $max_results = null, $timeout = null)
    {
        $period = $period ?? 'day';
        $min_magnitude = (float)($min_magnitude ?? 2.5);
        $max_results = (int)($max_results ?? 30);
        $timeout = (int)($timeout ?? 15);

        if ($max_results < 1) $max_results = 1;
        if ($max_results > 100) $max_results = 100;
        if ($min_magnitude < 0) $min_magnitude = 0;
        if ($min_magnitude > 9) $min_magnitude = 9;

        // Map period to USGS feed URL
        $feeds = [
            'hour' => 'https://earthquake.usgs.gov/earthquakes/feed/v1.0/summary/all_hour.geojson',
            'day' => 'https://earthquake.usgs.gov/earthquakes/feed/v1.0/summary/all_day.geojson',
            'week' => 'https://earthquake.usgs.gov/earthquakes/feed/v1.0/summary/all_week.geojson',
            'month' => 'https://earthquake.usgs.gov/earthquakes/feed/v1.0/summary/all_month.geojson',
        ];

        if (!isset($feeds[$period])) {
            $period = 'day';
        }
        $url = $feeds[$period];

        $context = stream_context_create([
            'http' => [
                'method' => 'GET',
                'timeout' => $timeout,
                'header' => "User-Agent: self-bootstrapping-agent/1.0\r\nAccept: application/json\r\n",
                'ignore_errors' => true,
            ]
        ]);

        $response = @file_get_contents($url, false, $context);

        if ($response === false) {
            return ['success' => false, 'error' => 'Failed to reach USGS earthquake API.'];
        }

        $data = json_decode($response, true);

        if ($data === null) {
            return ['success' => false, 'error' => 'Failed to parse API response as JSON.'];
        }

        if (!isset($data['features'])) {
            return ['success' => false, 'error' => 'Unexpected API response format.'];
        }

        $metadata = $data['metadata'] ?? [];
        $all_features = $data['features'];

        // Filter by minimum magnitude and limit
        $filtered = [];
        $all_magnitudes = [];
        $all_depths = [];

        foreach ($all_features as $f) {
            $props = $f['properties'] ?? [];
            $mag = (float)($props['mag'] ?? 0);
            
            if ($mag < $min_magnitude) continue;
            if (count($filtered) >= $max_results) break;
            
            $geom = $f['geometry']['coordinates'] ?? [0, 0, 0];
            $lon = (float)($geom[0] ?? 0);
            $lat = (float)($geom[1] ?? 0);
            $depth = (float)($geom[2] ?? 0);
            
            $time_ms = (int)($props['time'] ?? 0);
            $time_str = $time_ms > 0 ? gmdate('Y-m-d H:i:s', (int)($time_ms / 1000)) . ' UTC' : 'unknown';
            
            // Significance color
            $sig = (int)($props['sig'] ?? 0);
            $alert = $props['alert'] ?? null;
            $tsunami = (int)($props['tsunami'] ?? 0);
            
            // Determine severity
            $severity = 'minor';
            if ($mag >= 7.0) $severity = 'great';
            elseif ($mag >= 6.0) $severity = 'strong';
            elseif ($mag >= 5.0) $severity = 'moderate';
            elseif ($mag >= 4.0) $severity = 'light';
            
            // Place name cleanup
            $place = $props['place'] ?? 'Unknown location';
            
            $entry = [
                'magnitude' => $mag,
                'place' => $place,
                'time' => $time_str,
                'time_ms' => $time_ms,
                'coordinates' => ['latitude' => $lat, 'longitude' => $lon, 'depth_km' => round($depth, 2)],
                'severity' => $severity,
                'significance' => $sig,
                'alert' => $alert,
                'tsunami_warning' => $tsunami > 0,
                'felt_reports' => (int)($props['felt'] ?? 0),
                'url' => $props['url'] ?? '',
                'ids' => $props['ids'] ?? ($props['code'] ?? ''),
            ];
            
            $filtered[] = $entry;
            $all_magnitudes[] = $mag;
            $all_depths[] = $depth;
        }

        // Compute summary statistics
        $total_reported = count($all_features);
        $total_filtered = count($filtered);
        $max_mag = !empty($all_magnitudes) ? max($all_magnitudes) : 0;
        $min_mag = !empty($all_magnitudes) ? min($all_magnitudes) : 0;
        $avg_mag = !empty($all_magnitudes) ? round(array_sum($all_magnitudes) / count($all_magnitudes), 1) : 0;
        $avg_depth = !empty($all_depths) ? round(array_sum($all_depths) / count($all_depths), 0) : 0;

        // Count by severity
        $severity_counts = [];
        foreach ($filtered as $eq) {
            $sev = $eq['severity'];
            $severity_counts[$sev] = ($severity_counts[$sev] ?? 0) + 1;
        }

        // Find strongest
        $strongest = !empty($filtered) ? $filtered[0] : null;
        foreach ($filtered as $eq) {
            if ($eq['magnitude'] > ($strongest['magnitude'] ?? 0)) {
                $strongest = $eq;
            }
        }

        return [
            'success' => true,
            'period' => $period,
            'feed_url' => $url,
            'api_title' => $metadata['title'] ?? 'USGS Earthquakes',
